<span class="line"><span style="color:#89B4FA;font-style:italic;">    Denied</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#9399B2;">),</span><span style="color:#6C7086;font-style:italic;"> // Never allowed (e.g., blocked by policy)</span></span>
